DROP TABLE IF EXISTS `industry_case`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `industry_case` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `status` tinyint(4) NOT NULL DEFAULT '1',
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_keywords` text,
  `meta_description` text,
  `industry_case_id` int(11) NOT NULL,
  `lang_id` int(11) NOT NULL,
  `sort` int(11) NOT NULL DEFAULT '0',
  `is_top` tinyint(4) NOT NULL DEFAULT '0',
  `title` varchar(255) NOT NULL,
  `content` longtext,
  `thumbnail` varchar(512) DEFAULT NULL,
  `banner_url` varchar(512) DEFAULT NULL,
  `tags` json DEFAULT NULL,
  `solution_ids` json DEFAULT NULL,
  `related_industry_case_ids` json DEFAULT NULL,
  `view_count` int(11) NOT NULL DEFAULT '0',
  `related_product_ids` varchar(512) DEFAULT NULL,
  `related_solution_ids` varchar(512) DEFAULT NULL,
  `spec_line` varchar(128) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK_dcbc6f108e5ea8cb37307090f08` (`lang_id`),
  CONSTRAINT `FK_dcbc6f108e5ea8cb37307090f08` FOREIGN KEY (`lang_id`) REFERENCES `lang` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=127 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

