INSERT INTO `industry_case` VALUES (1,1,'2026-03-07 22:42:26.979368','2026-04-07 01:44:52.627289','案例-和苹果合作了',NULL,NULL,1,1,0,0,'案例-和苹果合作了','<p>案例-和苹果合作了</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,'[1]',NULL,0,'8,36,37','1',NULL),(2,1,'2026-03-07 22:42:37.809850','2026-03-22 21:51:24.896464','Case - Collaborated with Apple.',NULL,NULL,1,2,0,0,'Case - Collaborated with Apple.','<p>Case - Collaborated with Apple</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,NULL,NULL,0,NULL,NULL,NULL),(3,1,'2026-03-07 22:42:39.727895','2026-03-22 21:51:24.896464','ケース - アップルとの協力',NULL,NULL,1,3,0,0,'ケース - アップルとの協力','<p>ケース-アップルと提携しました</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,NULL,NULL,0,NULL,NULL,NULL),(4,1,'2026-03-07 22:42:41.605722','2026-03-22 21:51:24.896464','Caso - Colaboración con Apple',NULL,NULL,1,4,0,0,'Caso - Colaboración con Apple','<p>Casos - Colaboración con Apple</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,NULL,NULL,0,NULL,NULL,NULL),(5,1,'2026-03-07 22:42:43.173443','2026-03-22 21:51:24.896464','사례 - 애플과 협력했습니다.',NULL,NULL,1,5,0,0,'사례 - 애플과 협력했습니다.','<p>사례-애플과 협력했습니다</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,NULL,NULL,0,NULL,NULL,NULL),(6,1,'2026-03-07 22:42:44.804688','2026-03-22 21:51:24.896464','Caso - Collaborazione con Apple',NULL,NULL,1,6,0,0,'Caso - Collaborazione con Apple','<p>Caso - Collaborazione con Apple</p>','/uploads/202603/zimg-icase-1-thumb.webp','/uploads/202603/zimg-icase-1-banner.webp',NULL,NULL,NULL,0,NULL,NULL,NULL),(7,1,'2026-03-22 18:36:44.000000','2026-03-22 22:20:09.576100','江苏电网储能电站 | 鹏成新能源案例','江苏储能电站, 液冷储能, 电网侧储能, 200MW储能','鹏成新能源江苏200MW/400MWh液冷储能电站项目案例，为电网提供调峰调频服务。',2,1,1,1,'江苏电网200MW/400MWh液冷储能电站','<h3>项目概况</h3><p>本项目位于江苏省南京市，是华东地区规模最大的电网侧储能电站之一。项目总容量200MW/400MWh，采用鹏成新能源先进的液冷磷酸铁锂电池储能系统。</p><h3>技术方案</h3><ul><li>电池系统：磷酸铁锂电池，单舱容量5MWh，共80舱</li><li>温控系统：智能液冷技术，温差控制在3℃以内</li><li>PCS：1500V高压直流技术，效率≥98.5%</li><li>EMS：智能能量管理系统，支持AGC/AVC调度</li></ul><h3>项目亮点</h3><p>年调峰电量超过1.2亿千瓦时，参与电网调频辅助服务，有效缓解区域电网峰谷差压力。</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/zimg-icase-2-banner.webp','[\"电网储能\", \"液冷技术\", \"调峰调频\"]','[55, 49]',NULL,3580,'8,9','55,49',NULL),(8,1,'2026-03-22 18:36:44.000000','2026-04-07 01:44:21.488640','Jiangsu Grid Energy Storage | Pengcheng Case','Jiangsu energy storage, liquid cooled storage, grid-side storage, 200MW storage','Pengcheng New Energy Jiangsu 200MW/400MWh liquid-cooled energy storage station case study for grid peak shaving and frequency regulation.',2,2,1,1,'Jiangsu Grid 200MW/400MWh Liquid-Cooled Energy Storage Station','<h3>Project Overview</h3><p>This project is located in Nanjing, Jiangsu Province, one of the largest grid-side energy storage stations in East China. With a total capacity of 200MW/400MWh, it adopts Pengcheng\'s advanced liquid-cooled LFP battery energy storage system.</p><h3>Technical Solution</h3><ul><li>Battery System: Lithium iron phosphate batteries, 5MWh per container, 80 containers total</li><li>Thermal Management: Intelligent liquid cooling technology, temperature difference controlled within 3°C</li><li>PCS: 1500V high-voltage DC technology, efficiency ≥98.5%</li><li>EMS: Intelligent energy management system, supporting AGC/AVC dispatch</li></ul><h3>Project Highlights</h3><p>Annual peak-shaving electricity exceeds 120 million kWh, participates in grid frequency regulation ancillary services, effectively alleviating regional grid peak-valley pressure.</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/1774503241538-abe4500b6cd55a0c.png','[\"Grid Storage\", \"Liquid Cooling\", \"Peak Shaving\"]','[2]',NULL,4567,'8,9,10','2','600kW/1290kWh'),(9,1,'2026-03-22 18:36:44.000000','2026-03-22 22:20:09.576100','江蘇省エネルギー貯蔵 | 鵬成新能源ケース','江蘇エネルギー貯蔵, 液冷貯蔵, グリッド側貯蔵, 200MW貯蔵','鵬成新能源の江蘇省200MW/400MWh液冷エネルギー貯蔵発電所ケーススタディ。',2,3,1,1,'江蘇省電力網200MW/400MWh液冷エネルギー貯蔵発電所','<h3>プロジェクト概要</h3><p>本プロジェクトは江蘇省南京市に位置し、華東地域最大規模のグリッド側エネルギー貯蔵発電所の一つです。総容量200MW/400MWhで、鵬成新能源の先進的な液冷LFPバッテリー貯蔵システムを採用しています。</p><h3>技術ソリューション</h3><ul><li>バッテリーシステム：リチウム鉄リン酸バッテリー、コンテナあたり5MWh、計80コンテナ</li><li>熱管理：インテリジェント液冷技術、温度差を3℃以内に制御</li><li>PCS：1500V高圧直流技術、効率≥98.5%</li><li>EMS：インテリジェントエネルギー管理システム、AGC/AVC調度をサポート</li></ul><h3>プロジェクトのハイライト</h3><p>年間ピークシェービング電力は1.2億kWhを超え、グリッド周波数調整補助サービスに参加し、地域グリッドのピーク・オフピーク圧力を効果的に緩和しています。</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/zimg-icase-2-banner.webp','[\"グリッド貯蔵\", \"液冷技術\", \"ピークシェービング\"]','[2]',NULL,3245,'','2',NULL),(10,1,'2026-03-22 18:36:44.000000','2026-03-22 22:20:09.576100','Almacenamiento Jiangsu | Caso Pengcheng','Jiangsu almacenamiento, enfriamiento líquido, almacenamiento red, 200MW','Caso de estudio de Pengcheng New Energy Jiangsu 200MW/400MWh con enfriamiento líquido.',2,4,1,1,'Estación de Almacenamiento Jiangsu 200MW/400MWh con Enfriamiento Líquido','<h3>Resumen del Proyecto</h3><p>Este proyecto está ubicado en Nanjing, provincia de Jiangsu, una de las estaciones de almacenamiento de energía del lado de la red más grandes de China Oriental. Con una capacidad total de 200MW/400MWh, adopta el sistema avanzado de almacenamiento de baterías LFP con enfriamiento líquido de Pengcheng.</p><h3>Solución Técnica</h3><ul><li>Sistema de Baterías: Baterías de fosfato de hierro y litio, 5MWh por contenedor, 80 contenedores en total</li><li>Gestión Térmica: Tecnología de enfriamiento líquido inteligente, diferencia de temperatura controlada dentro de 3°C</li><li>PCS: Tecnología DC de alta tensión 1500V, eficiencia ≥98.5%</li><li>EMS: Sistema de gestión de energía inteligente, compatible con despacho AGC/AVC</li></ul><h3>Puntos Destacados</h3><p>La electricidad de reducción de picos anual excede los 120 millones de kWh, participa en servicios auxiliares de regulación de frecuencia.</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/zimg-icase-2-banner.webp','[\"Almacenamiento Red\", \"Enfriamiento Líquido\", \"Reducción Picos\"]','[2]',NULL,2890,'','2',NULL),(11,1,'2026-03-22 18:36:44.000000','2026-03-22 22:20:09.576100','장쑤 에너지 저장 | 鹏成新能源 케이스','장쑤 에너지 저장, 액체 냉각 저장, 전력망 측 저장, 200MW','鹏成新能源 장쑤 200MW/400MWh 액체 냉각 에너지 저장 발전소 케이스 연구.',2,5,1,1,'장쑤 전력망 200MW/400MWh 액체 냉각 에너지 저장 발전소','<h3>프로젝트 개요</h3><p>본 프로젝트는 장쑤성 남경시에 위치하며, 화동 지역 최대 규모의 전력망 측 에너지 저장 발전소 중 하나입니다. 총 용량 200MW/400MWh로 鹏成新能源의 첨단 액체 냉각 LFP 배터리 저장 시스템을 채택했습니다.</p><h3>기술 솔루션</h3><ul><li>배터리 시스템: 인산철리튬 배터리, 컨테이너당 5MWh, 총 80컨테이너</li><li>열 관리: 지능형 액체 냉각 기술, 온도 차를 3℃ 이내로 제어</li><li>PCS: 1500V 고압 직류 기술, 효율 ≥98.5%</li><li>EMS: 지능형 에너지 관리 시스템, AGC/AVC 조度 지원</li></ul><h3>프로젝트 하이라이트</h3><p>연간 피크 쉐이빙 전력이 1.2억 kWh를 초과하며 전력망 주파수 조절 보조 서비스에 참여합니다.</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/zimg-icase-2-banner.webp','[\"전력망 저장\", \"액체 냉각\", \"피크 쉐이빙\"]','[2]',NULL,2456,'','2',NULL),(12,1,'2026-03-22 18:36:44.000000','2026-03-22 22:20:09.576100','Accumulo Jiangsu | Caso Pengcheng','Jiangsu accumulo, raffreddamento liquido, accumulo lato rete, 200MW','Caso di studio Pengcheng New Energy Jiangsu 200MW/400MWh con raffreddamento a liquido.',2,6,1,1,'Stazione di Accumulo Jiangsu 200MW/400MWh con Raffreddamento a Liquido','<h3>Panoramica del Progetto</h3><p>Questo progetto è situato a Nanchino, provincia del Jiangsu, una delle più grandi stazioni di accumulo energia lato rete della Cina orientale. Con una capacità totale di 200MW/400MWh, adotta il sistema avanzato di accumulo batterie LFP con raffreddamento a liquido di Pengcheng.</p><h3>Soluzione Tecnica</h3><ul><li>Sistema Batterie: Batterie al fosfato di ferro e litio, 5MWh per container, 80 container totali</li><li>Gestione Termica: Tecnologia di raffreddamento a liquido intelligente, differenza temperatura controllata entro 3°C</li><li>PCS: Tecnologia DC ad alta tensione 1500V, efficienza ≥98.5%</li><li>EMS: Sistema gestione energia intelligente, supporto dispatch AGC/AVC</li></ul><h3>Punti Salienti</h3><p>L\'elettricità annuale di shaving picchi supera i 120 milioni di kWh, partecipa ai servizi ausiliari di regolazione frequenza.</p>','/uploads/202603/zimg-icase-2-thumb.webp','/uploads/202603/zimg-icase-2-banner.webp','[\"Accumulo Rete\", \"Raffreddamento Liquido\", \"Shaving Picchi\"]','[2]',NULL,2134,'','2',NULL),(13,1,'2026-03-22 18:37:02.000000','2026-03-22 22:20:09.583694','山东风电储能项目 | 鹏成新能源案例','山东风电, 风电配储, 新能源储能, 弃风限电','鹏成新能源山东华电100MW风电配套30MW/60MWh储能项目案例。',3,1,2,1,'山东华电100MW风电配储项目','<h3>项目概况</h3><p>本项目位于山东省滨州市，华电集团首个百兆瓦级风电配套储能项目。配置储能容量30MW/60MWh，有效解决风电场弃风限电问题。</p><h3>技术方案</h3><ul><li>储能配比：按风电装机容量的30%配置</li><li>电池类型：磷酸铁锂电池，循环寿命≥6000次</li><li>接入方式：35kV升压站并网</li><li>运行模式：平滑出力+跟踪计划+调频辅助</li></ul><h3>项目成效</h3><p>弃风率降低12个百分点，风电场年均利用小时数提升约280小时，年增收超过1500万元。</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"风电配储\", \"新能源\", \"弃风消纳\"]','[2]',NULL,2890,'','2',NULL),(14,1,'2026-03-22 18:37:02.000000','2026-04-07 01:41:40.841733','Shandong Wind Storage | Pengcheng Case','Shandong wind power, wind farm storage, renewable storage, curtailment','Pengcheng New Energy Shandong Huadian 100MW wind farm with 30MW/60MWh storage project case.',3,2,2,1,'Shandong Huadian 100MW Wind Farm + Storage Project','<h3>Project Overview</h3><p>Located in Binzhou City, Shandong Province, this is Huadian Group\'s first 100MW-scale wind farm with supporting energy storage. The 30MW/60MWh storage system effectively addresses wind curtailment issues.</p><h3>Technical Solution</h3><ul><li>Storage Ratio: 30% of wind farm installed capacity</li><li>Battery Type: Lithium iron phosphate, cycle life ≥6000 cycles</li><li>Grid Connection: 35kV step-up substation</li><li>Operating Modes: Output smoothing + schedule tracking + frequency regulation</li></ul><h3>Project Results</h3><p>Wind curtailment rate reduced by 12 percentage points, annual utilization hours increased by approximately 280 hours, annual revenue increased by over 15 million yuan.</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"Wind+Storage\", \"Renewable Energy\", \"Curtailment Reduction\"]','[2, 56]',NULL,3456,'8,9,10','2,56','600kW/1290kWh'),(15,1,'2026-03-22 18:37:02.000000','2026-03-22 22:20:09.583694','山東風力貯蔵 | 鵬成新能源ケース','山東風力, 風力発電貯蔵, 再生可能貯蔵, カットアウト','鵬成新能源山東華電100MW風力発電所30MW/60MWh貯蔵プロジェクトケーススタディ。',3,3,2,1,'山東華電100MW風力発電+貯蔵プロジェクト','<h3>プロジェクト概要</h3><p>山東省浜州市に位置し、華電グループ初の100MW級風力発電所とエネルギー貯蔵設備を備えたプロジェクトです。30MW/60MWhの貯蔵システムは風力カットアウト問題を効果的に解決します。</p><h3>技術ソリューション</h3><ul><li>貯蔵比率：風力発電所設備容量の30%</li><li>バッテリータイプ：リチウム鉄リン酸、サイクル寿命≥6000サイクル</li><li>グリッド接続：35kV昇圧変電所</li><li>運転モード：出力平滑化+スケジュール追跡+周波数調整</li></ul><h3>プロジェクト成果</h3><p>風力カットアウト率が12ポイント低下、年間利用時間数が約280時間増加、年間収益が1500万元以上増加しました。</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"風力+貯蔵\", \"再生可能エネルギー\", \"カットアウト低減\"]','[2]',NULL,2789,'','2',NULL),(16,1,'2026-03-22 18:37:02.000000','2026-03-22 22:20:09.583694','Almacenamiento Eólico Shandong | Caso Pengcheng','Shandong eólica, almacenamiento eólico, almacenamiento renovable, limitación','Caso de estudio Pengcheng New Energy Shandong Huadian 100MW eólica con almacenamiento.',3,4,2,1,'Proyecto Shandong Huadian 100MW Eólica + Almacenamiento','<h3>Resumen del Proyecto</h3><p>Ubicado en la ciudad de Binzhou, provincia de Shandong, este es el primer proyecto eólico de escala de 100MW del Grupo Huadian con almacenamiento de energía de apoyo. El sistema de almacenamiento de 30MW/60MWh aborda efectivamente los problemas de limitación eólica.</p><h3>Solución Técnica</h3><ul><li>Relación de Almacenamiento: 30% de la capacidad instalada del parque eólico</li><li>Tipo de Batería: Fosfato de hierro y litio, vida útil ≥6000 ciclos</li><li>Conexión a Red: Subestación elevadora de 35kV</li><li>Modos de Operación: Suavizado de salida + seguimiento de programa + regulación de frecuencia</li></ul><h3>Resultados del Proyecto</h3><p>Tasa de limitación eólica reducida en 12 puntos porcentuales, horas anuales de utilización aumentadas aproximadamente 280 horas.</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"Eólica+Almacenamiento\", \"Energía Renovable\", \"Reducción Limitación\"]','[2]',NULL,2345,'','2',NULL),(17,1,'2026-03-22 18:37:02.000000','2026-03-22 22:20:09.583694','산둥 풍력 저장 | 鹏成新能源 케이스','산둥 풍력, 풍력발전 저장, 재생 저장, 제한','鹏成新能源 산둥 화전 100MW 풍력발전소 30MW/60MWh 저장 프로젝트 케이스 연구.',3,5,2,1,'산둥 화전 100MW 풍력발전+저장 프로젝트','<h3>프로젝트 개요</h3><p>산둥성 빈저우시에 위치하며, 화전그룹의 첫 번째 100MW급 풍력발전소와 에너지 저장 장비를 갖춘 프로젝트입니다. 30MW/60MWh 저장 시스템은 풍력발전 제한 문제를 효과적으로 해결합니다.</p><h3>기술 솔루션</h3><ul><li>저장 비율: 풍력발전소 설비 용량의 30%</li><li>배터리 유형: 인산철리튬, 사이클 수명≥6000사이클</li><li>계통 연계: 35kV 승압 변전소</li><li>운전 모드: 출력 평활화+스케줄 추적+주파수 조절</li></ul><h3>프로젝트 성과</h3><p>풍력발전 제한률이 12퍼센트포인트 감소, 연간 이용 시간이 약 280시간 증가, 연간 수익이 1500만원 이상 증가했습니다.</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"풍력+저장\", \"신재생에너지\", \"제한 감소\"]','[2]',NULL,2123,'','2',NULL),(18,1,'2026-03-22 18:37:02.000000','2026-03-22 22:20:09.583694','Accumulo Eolico Shandong | Caso Pengcheng','Shandong eolico, accumulo eolico, accumulo rinnovabile, limitazione','Caso di studio Pengcheng New Energy Shandong Huadian 100MW eolico con accumulo.',3,6,2,1,'Progetto Shandong Huadian 100MW Eolico + Accumulo','<h3>Panoramica del Progetto</h3><p>Situato nella città di Binzhou, provincia dello Shandong, questo è il primo progetto eolico su scala 100MW del Gruppo Huadian con accumulo di energia di supporto. Il sistema di accumulo da 30MW/60MWh affronta efficacemente i problemi di limitazione eolica.</p><h3>Soluzione Tecnica</h3><ul><li>Rapporto Accumulo: 30% della capacità installata del parco eolico</li><li>Tipo di Batteria: Fosfato di ferro e litio, vita ciclica ≥6000 cicli</li><li>Connessione di Rete: Sottostazione elevatrice 35kV</li><li>Modalità Operative: Levigatura output + tracciamento programma + regolazione frequenza</li></ul><h3>Risultati del Progetto</h3><p>Tasso di limitazione eolica ridotto di 12 punti percentuali, ore annuali di utilizzo aumentate di circa 280 ore.</p>','/uploads/202603/zimg-icase-3-thumb.webp','/uploads/202603/zimg-icase-3-banner.webp','[\"Eolico+Accumulo\", \"Energia Rinnovabile\", \"Riduzione Limitazione\"]','[2]',NULL,1890,'','2',NULL),(19,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','浙江工商业储能 | 鹏成新能源案例','浙江储能, 工商业储能, 峰谷套利, 需量控制','鹏成新能源浙江工业园区10MW/20MWh工商业储能系统项目案例。',4,1,3,0,'浙江工商业园区储能系统','<h3>项目概况</h3><p>浙江省杭州市某工业园区10MW/20MWh工商业储能项目，采用峰谷套利+需量控制+备用电源三位一体运行模式。</p><h3>技术方案</h3><ul><li>系统配置：2小时储能系统，支持每日两充两放</li><li>应用场景：峰谷套利、需量管理、应急备电</li><li>接入电压：10kV中压并网</li><li>消防系统：Pack级探测+全氟己酮消防</li></ul><h3>经济效益</h3><p>年节省电费约450万元，投资回收期约5.2年，系统寿命期内累计收益超过3000万元。</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"工商业储能\", \"峰谷套利\", \"需量管理\"]','[2]',NULL,3245,'','2',NULL),(20,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','Zhejiang Industrial Storage | Pengcheng Case','Zhejiang storage, C&I storage, peak-valley arbitrage, demand control','Pengcheng New Energy Zhejiang industrial park 10MW/20MWh C&I energy storage system case.',4,2,3,0,'Zhejiang Industrial Park Energy Storage System','<h3>Project Overview</h3><p>A 10MW/20MWh C&I energy storage project at an industrial park in Hangzhou, Zhejiang Province. The system operates in a three-in-one mode: peak-valley arbitrage + demand control + backup power.</p><h3>Technical Solution</h3><ul><li>System Configuration: 2-hour storage system supporting twice daily charge/discharge</li><li>Application Scenarios: Peak-valley arbitrage, demand management, emergency backup</li><li>Connection Voltage: 10kV medium-voltage grid connection</li><li>Fire Protection: Pack-level detection + FK-5-1-12 fire suppression</li></ul><h3>Economic Benefits</h3><p>Annual electricity savings of approximately 4.5 million yuan, payback period of about 5.2 years, cumulative benefits exceeding 30 million yuan over system lifetime.</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"C&I Storage\", \"Peak Shaving\", \"Demand Management\"]','[2]',NULL,4123,'','2',NULL),(21,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','浙江省産業貯蔵 | 鵬成新能源ケース','浙江省貯蔵, 商産業貯蔵, ピークアービトラージ, 需要制御','鵬成新能源浙江省工業団地10MW/20MWh商産業エネルギー貯蔵システムケーススタディ。',4,3,3,0,'浙江省工業団地エネルギー貯蔵システム','<h3>プロジェクト概要</h3><p>浙江省杭州市の工業団地における10MW/20MWh商業・産業用エネルギー貯蔵プロジェクト。ピーク・オフピークアービトラージ+需要制御+バックアップ電源の三位一体運転モードを採用。</p><h3>技術ソリューション</h3><ul><li>システム構成：2時間貯蔵システム、1日2回の充放電をサポート</li><li>応用シナリオ：ピーク・オフピークアービトラージ、需要管理、緊急バックアップ</li><li>接続電圧：10kV中圧グリッド接続</li><li>消防システム：パックレベル検出+FK-5-1-12消火</li></ul><h3>経済効果</h3><p>年間電気料金節約約450万元、投資回収期間約5.2年、システム寿命期間内累積収益3000万元以上。</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"C&I貯蔵\", \"ピークシェービング\", \"需要管理\"]','[2]',NULL,3456,'','2',NULL),(22,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','Almacenamiento Industrial Zhejiang | Caso Pengcheng','Zhejiang almacenamiento, almacenamiento C&I, arbitraje pico-valle, control demanda','Caso de estudio Pengcheng New Energy parque industrial Zhejiang 10MW/20MWh C&I.',4,4,3,0,'Sistema de Almacenamiento Parque Industrial Zhejiang','<h3>Resumen del Proyecto</h3><p>Proyecto de almacenamiento de energía C&I de 10MW/20MWh en un parque industrial en Hangzhou, provincia de Zhejiang. El sistema opera en modo tres-en-uno: arbitraje pico-valle + control de demanda + energía de respaldo.</p><h3>Solución Técnica</h3><ul><li>Configuración del Sistema: Sistema de almacenamiento de 2 horas, soporta dos ciclos de carga/descarga diarios</li><li>Escenarios de Aplicación: Arbitraje pico-valle, gestión de demanda, respaldo de emergencia</li><li>Voltaje de Conexión: Conexión a red de media tensión 10kV</li><li>Protección contra Incendios: Detección a nivel de pack + supresión FK-5-1-12</li></ul><h3>Beneficios Económicos</h3><p>Ahorro anual de electricidad de aproximadamente 4.5 millones de yuanes, período de recuperación de aproximadamente 5.2 años.</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"Almacenamiento C&I\", \"Reducción Picos\", \"Gestión Demanda\"]','[2]',NULL,2890,'','2',NULL),(23,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','저장장 공업 저장 | 鹏成新能源 케이스','저장장 저장, 상공업 저장, 피크 차익거래, 수요 제어','鹏成新能源 저장장 공업단지 10MW/20MWh 상공업 에너지 저장 시스템 케이스 연구.',4,5,3,0,'저장장 공업단지 에너지 저장 시스템','<h3>프로젝트 개요</h3><p>저장장성 항저우시의 공업단지에서 10MW/20MWh 상공업용 에너지 저장 프로젝트입니다. 시스템은 피크-오프피크 차익거래+수요제어+비상전원의 3-in-1 모드로 운전합니다.</p><h3>기술 솔루션</h3><ul><li>시스템 구성: 2시간 저장 시스템, 하루 2회 충방전 지원</li><li>응용 시나리오: 피크-오프피크 차익거래, 수요 관리, 응급 백업</li><li>연계 전압: 10kV 중압 계통 연계</li><li>소방 시스템: 팩 레벨 탐지+FK-5-1-12 소화</li></ul><h3>경제적 효익</h3><p>연간 전기 요금 절약 약 450만원, 투자 회수 기간 약 5.2년, 시스템 수명 기간 내 누적 수익 3000만원 이상.</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"상공업 저장\", \"피크 쉐이빙\", \"수요 관리\"]','[2]',NULL,2567,'','2',NULL),(24,1,'2026-03-22 18:37:19.000000','2026-03-22 18:37:19.000000','Accumulo Industriale Zhejiang | Caso Pengcheng','Zhejiang accumulo, accumulo C&I, arbitraggio picco-vall, controllo domanda','Caso di studio Pengcheng New Energy parco industriale Zhejiang 10MW/20MWh C&I.',4,6,3,0,'Sistema di Accumulo Parco Industriale Zhejiang','<h3>Panoramica del Progetto</h3><p>Progetto di accumulo energia C&I da 10MW/20MWh in un parco industriale a Hangzhou, provincia dello Zhejiang. Il sistema opera in modalità tre-in-uno: arbitraggio picco-vall + controllo domanda + alimentazione di emergenza.</p><h3>Soluzione Tecnica</h3><ul><li>Configurazione Sistema: Sistema di accumulo 2 ore, supporta due cicli di carica/scarica giornalieri</li><li>Scenari Applicativi: Arbitraggio picco-vall, gestione domanda, backup emergenza</li><li>Tensione Connessione: Connessione rete media tensione 10kV</li><li>Sistema Antincendio: Rilevazione a livello di pack + soppressione FK-5-1-12</li></ul><h3>Benefici Economici</h3><p>Risparmio annuo elettricità di circa 4.5 milioni di yuan, periodo di ripagamento di circa 5.2 anni.</p>','/uploads/cases/case-4-thumb.jpg','/uploads/cases/case-4-banner.jpg','[\"Accumulo C&I\", \"Shaving Picchi\", \"Gestione Domanda\"]','[2]',NULL,2234,'','2',NULL),(25,1,'2026-03-22 18:37:35.000000','2026-03-22 18:37:35.000000','广东调频储能 | 鹏成新能源案例','广东储能, 电网调频, AGC储能, 辅助服务市场','鹏成新能源广东电网20MW/10MWh调频储能电站项目案例。',5,1,4,1,'广东电网调频储能项目','<h3>项目概况</h3><p>广东省电网侧20MW/10MWh调频储能电站，响应南方区域调频辅助服务市场，提供电网AGC调频服务。</p><h3>技术特点</h3><ul><li>响应速度：毫秒级功率响应，满足AGC秒级调度</li><li>调节精度：功率控制精度±1%</li><li>循环寿命：调频工况下循环寿命≥10年</li><li>容量配置：按照调频功率需求优化配置储能容量</li></ul><h3>市场表现</h3><p>年调频里程超过30万MW，调频性能指标K值达2.8以上，年调频收益超过2000万元。</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"电网调频\", \"AGC\", \"辅助服务\"]','[2]',NULL,4567,'','2',NULL),(26,1,'2026-03-22 18:37:35.000000','2026-03-26 12:32:23.000000','Guangdong Frequency Storage | Pengcheng Case','Guangdong storage, grid frequency regulation, AGC storage, ancillary market','Pengcheng New Energy Guangdong grid 20MW/10MWh frequency regulation storage station case.',5,2,4,1,'Guangdong Grid Frequency Regulation Storage Project','<h3>Project Overview</h3><p>A 20MW/10MWh grid-side frequency regulation energy storage station in Guangdong Province, responding to the southern regional frequency regulation ancillary service market and providing grid AGC frequency regulation services.</p><h3>Technical Features</h3><ul><li>Response Speed: Millisecond-level power response, meeting AGC second-level dispatch</li><li>Regulation Accuracy: Power control accuracy ±1%</li><li>Cycle Life: Cycle life ≥10 years under frequency regulation conditions</li><li>Capacity Configuration: Optimized storage capacity based on frequency regulation power requirements</li></ul><h3>Market Performance</h3><p>Annual frequency regulation mileage exceeds 300,000 MW, frequency regulation performance index K-value above 2.8, annual frequency regulation revenue exceeds 20 million yuan.</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"Frequency Regulation\", \"AGC\", \"Ancillary Services\"]','[2]',NULL,5234,NULL,'2','600kW/1290kWh'),(27,1,'2026-03-22 18:37:35.000000','2026-03-22 18:37:35.000000','広東調整貯蔵 | 鵬成新能源ケース','広東貯蔵, グリッド周波数調整, AGC貯蔵, 補助市場','鵬成新能源広東省電力網20MW/10MWh周波数調整貯蔵発電所ケーススタディ。',5,3,4,1,'広東省電力網周波数調整貯蔵プロジェクト','<h3>プロジェクト概要</h3><p>広東省のグリッド側20MW/10MWh周波数調整エネルギー貯蔵発電所。南方地域の周波数調整補助サービス市場に対応し、グリッドAGC周波数調整サービスを提供します。</p><h3>技術特徴</h3><ul><li>応答速度：ミリ秒レベルのパワー応答、AGC秒級調度に対応</li><li>調整精度：パワー制御精度±1%</li><li>サイクル寿命：周波数調整条件下でサイクル寿命≥10年</li><li>容量構成：周波数調整パワー要件に基づき最適化された貯蔵容量</li></ul><h3>市場パフォーマンス</h3><p>年間周波数調整マイレージが30万MWを超え、周波数調整性能指標K値は2.8以上、年間調整収益は2000万元を超えます。</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"周波数調整\", \"AGC\", \"補助サービス\"]','[2]',NULL,4123,'','2',NULL),(28,1,'2026-03-22 18:37:35.000000','2026-03-22 18:37:35.000000','Almacenamiento Regulación Cantón | Caso Pengcheng','Cantón almacenamiento, regulación frecuencia red, almacenamiento AGC, mercado auxiliar','Caso de estudio Pengcheng New Energy red Cantón 20MW/10MWh regulación frecuencia.',5,4,4,1,'Proyecto Almacenamiento Regulación Frecuencia Red Cantón','<h3>Resumen del Proyecto</h3><p>Estación de almacenamiento de energía del lado de la red de 20MW/10MWh para regulación de frecuencia en la provincia de Cantón, respondiendo al mercado de servicios auxiliares de regulación de frecuencia regional del sur.</p><h3>Características Técnicas</h3><ul><li>Velocidad de Respuesta: Respuesta de potencia a nivel de milisegundos, cumpliendo con el despacho AGC a nivel de segundos</li><li>Precisión de Regulación: Precisión de control de potencia ±1%</li><li>Vida Útil Ciclo: Vida útil ciclo ≥10 años bajo condiciones de regulación de frecuencia</li><li>Configuración de Capacidad: Capacidad de almacenamiento optimizada según requisitos de potencia de regulación</li></ul><h3>Rendimiento de Mercado</h3><p>El kilometraje anual de regulación de frecuencia excede los 300,000 MW, el índice de rendimiento K supera 2.8.</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"Regulación Frecuencia\", \"AGC\", \"Servicios Auxiliares\"]','[2]',NULL,3456,'','2',NULL),(29,1,'2026-03-22 18:37:35.000000','2026-03-22 18:37:35.000000','광동 조절 저장 | 鹏成新能源 케이스','광동 저장, 전력망 주파수 조절, AGC 저장, 보조 시장','鹏成新能源 광동 전력망 20MW/10MWh 주파수 조절 저장 발전소 케이스 연구.',5,5,4,1,'광동 전력망 주파수 조절 저장 프로젝트','<h3>프로젝트 개요</h3><p>광동성 전력망 측 20MW/10MWh 주파수 조절 에너지 저장 발전소로, 남부 지역 주파수 조절 보조 서비스 시장에 대응하며 전력망 AGC 주파수 조절 서비스를 제공합니다.</p><h3>기술 특징</h3><ul><li>응답 속도: 밀리초 레벨 전력 응답, AGC 초급 조度 충족</li><li>조절 정확도: 전력 제어 정확도 ±1%</li><li>사이클 수명: 주파수 조절 조건에서 사이클 수명≥10년</li><li>용량 구성: 주파수 조절 전력 수요에 따라 최적화된 저장 용량</li></ul><h3>시장 성과</h3><p>연간 주파수 조절 마일리지가 30만MW를 초과하며, 주파수 조절 성능 지표 K값이 2.8 이상, 연간 조절 수익이 2000만원을 초과합니다.</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"주파수 조절\", \"AGC\", \"보조 서비스\"]','[2]',NULL,3123,'','2',NULL),(30,1,'2026-03-22 18:37:35.000000','2026-03-22 18:37:35.000000','Accumulo Regolazione Canton | Caso Pengcheng','Canton accumulo, regolazione frequenza rete, accumulo AGC, mercato ausiliario','Caso di studio Pengcheng New Energy rete Canton 20MW/10MWh regolazione frequenza.',5,6,4,1,'Progetto Accumulo Regolazione Frequenza Rete Canton','<h3>Panoramica del Progetto</h3><p>Stazione di accumulo energia lato rete 20MW/10MWh per regolazione frequenza nella provincia del Canton, che risponde al mercato dei servizi ausiliari di regolazione frequenza della regione meridionale.</p><h3>Caratteristiche Tecniche</h3><ul><li>Velocità Risposta: Risposta di potenza a livello di millisecondi, soddisfacendo il dispatch AGC a livello di secondi</li><li>Precisione Regolazione: Precisione controllo potenza ±1%</li><li>Vita Ciclica: Vita ciclica ≥10 anni in condizioni di regolazione frequenza</li><li>Configurazione Capacità: Capacità di accumulo ottimizzata in base ai requisiti di potenza di regolazione</li></ul><h3>Prestazioni di Mercato</h3><p>Il chilometraggio annuale di regolazione frequenza supera i 300.000 MW, l\'indice di prestazione K supera 2.8.</p>','/uploads/cases/case-5-thumb.jpg','/uploads/cases/case-5-banner.jpg','[\"Regolazione Frequenza\", \"AGC\", \"Servizi Ausiliari\"]','[2]',NULL,2789,'','2',NULL),(31,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','内蒙古光伏储能 | 鹏成新能源案例','内蒙古储能, 光伏配储, 太阳能储能, 出力平滑','鹏成新能源内蒙古鄂尔多斯50MW光伏配套15MW/30MWh储能项目案例。',6,1,5,0,'内蒙古光伏配储项目','<h3>项目概况</h3><p>内蒙古鄂尔多斯50MW光伏电站配套15MW/30MWh储能系统，解决光伏出力波动性问题，提升电能质量。</p><h3>技术方案</h3><ul><li>光伏装机：50MW单晶PERC组件</li><li>储能配比：按光伏装机30%配置储能</li><li>储能时长：2小时储能系统</li><li>功能配置：平滑出力、跟踪计划、削峰填谷</li></ul><h3>运行效果</h3><p>光伏发电预测准确率提升至95%以上，出力波动率降低80%，有效减少电网调度压力。</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"光伏配储\", \"新能源\", \"出力平滑\"]','[2]',NULL,3890,'','2',NULL),(32,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','Inner Mongolia Solar Storage | Pengcheng Case','Inner Mongolia storage, solar storage, PV storage, output smoothing','Pengcheng New Energy Inner Mongolia Ordos 50MW solar with 15MW/30MWh storage case.',6,2,5,0,'Inner Mongolia Solar + Storage Project','<h3>Project Overview</h3><p>A 15MW/30MWh energy storage system supporting a 50MW solar PV plant in Ordos, Inner Mongolia, addressing solar output fluctuation issues and improving power quality.</p><h3>Technical Solution</h3><ul><li>Solar Installation: 50MW monocrystalline PERC modules</li><li>Storage Ratio: 30% storage capacity relative to solar installation</li><li>Storage Duration: 2-hour energy storage system</li><li>Functions: Output smoothing, schedule tracking, peak shaving and valley filling</li></ul><h3>Operational Results</h3><p>Solar power forecasting accuracy improved to above 95%, output fluctuation rate reduced by 80%, effectively reducing grid dispatch pressure.</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"Solar+Storage\", \"Renewable Energy\", \"Output Smoothing\"]','[2]',NULL,4567,'','2',NULL),(33,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','内モンゴル太陽光貯蔵 | 鵬成新能源ケース','内モンゴル貯蔵, 太陽光貯蔵, PV貯蔵, 出力平滑化','鵬成新能源内モンゴル鄂爾多斯50MW太陽光15MW/30MWh貯蔵ケーススタディ。',6,3,5,0,'内モンゴル太陽光+貯蔵プロジェクト','<h3>プロジェクト概要</h3><p>内モンゴル鄂爾多斯の50MW太陽光発電所に15MW/30MWhのエネルギー貯蔵システムを配備し、太陽光の出力変動問題を解決し、電力品質を向上させます。</p><h3>技術ソリューション</h3><ul><li>太陽光設備：50MW単結晶PERCモジュール</li><li>貯蔵比率：太陽光設備容量の30%の貯蔵容量</li><li>貯蔵時間：2時間エネルギー貯蔵システム</li><li>機能：出力平滑化、スケジュール追跡、ピークシェービング</li></ul><h3>運転結果</h3><p>太陽光発電予測精度が95%以上に向上し、出力変動率が80%低減されました。</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"太陽光+貯蔵\", \"再生可能エネルギー\", \"出力平滑化\"]','[2]',NULL,3890,'','2',NULL),(34,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','Almacenamiento Solar Mongolia Interior | Caso Pengcheng','Mongolia Interior almacenamiento, almacenamiento solar, PV almacenamiento','Caso de estudio Pengcheng New Energy Mongolia Interior Ordos 50MW solar con almacenamiento.',6,4,5,0,'Proyecto Solar + Almacenamiento Mongolia Interior','<h3>Resumen del Proyecto</h3><p>Sistema de almacenamiento de energía de 15MW/30MWh para una planta solar PV de 50MW en Ordos, Mongolia Interior, que aborda los problemas de fluctuación de salida solar y mejora la calidad de energía.</p><h3>Solución Técnica</h3><ul><li>Instalación Solar: Módulos PERC monocristalinos de 50MW</li><li>Relación de Almacenamiento: 30% de capacidad de almacenamiento relativa a la instalación solar</li><li>Duración de Almacenamiento: Sistema de almacenamiento de energía de 2 horas</li><li>Funciones: Suavizado de salida, seguimiento de programa, reducción de picos</li></ul><h3>Resultados Operativos</h3><p>La precisión de pronóstico de energía solar mejoró a más del 95%, la tasa de fluctuación de salida se redujo en un 80%.</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"Solar+Almacenamiento\", \"Energía Renovable\", \"Suavizado Salida\"]','[2]',NULL,3234,'','2',NULL),(35,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','내몽고 태양광 저장 | 鹏成新能源 케이스','내몽고 저장, 태양광 저장, PV 저장, 출력 평활화','鹏成新能源 내몽고 어얼둬쓰 50MW 태양광 15MW/30MWh 저장 케이스 연구.',6,5,5,0,'내몽고 태양광+저장 프로젝트','<h3>프로젝트 개요</h3><p>내몽고 어얼둬쓰의 50MW 태양광 발전소에 15MW/30MWh 에너지 저장 시스템을 구축하여 태양광 출력 변동 문제를 해결하고 전력 품질을 개선합니다.</p><h3>기술 솔루션</h3><ul><li>태양광 설비: 50MW 단결정 PERC 모듈</li><li>저장 비율: 태양광 설비 용량의 30% 저장 용량</li><li>저장 시간: 2시간 에너지 저장 시스템</li><li>기능: 출력 평활화, 스케줄 추적, 피크 쉐이빙</li></ul><h3>운영 결과</h3><p>태양광 발전 예측 정확도가 95% 이상으로 향상되었으며, 출력 변동률이 80% 감소했습니다.</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"태양광+저장\", \"신재생에너지\", \"출력 평활화\"]','[2]',NULL,2890,'','2',NULL),(36,1,'2026-03-22 18:37:51.000000','2026-03-22 18:37:51.000000','Accumulo Solare Mongolia Interna | Caso Pengcheng','Mongolia Interna accumulo, accumulo solare, PV accumulo','Caso di studio Pengcheng New Energy Mongolia Interna Ordos 50MW solare con accumulo.',6,6,5,0,'Progetto Solare + Accumulo Mongolia Interna','<h3>Panoramica del Progetto</h3><p>Sistema di accumulo energia da 15MW/30MWh per un impianto solare PV da 50MW a Ordos, Mongolia Interna, che affronta i problemi di fluttuazione dell\'output solare e migliora la qualità dell\'energia.</p><h3>Soluzione Tecnica</h3><ul><li>Impianto Solare: Moduli PERC monocristallini da 50MW</li><li>Rapporto Accumulo: 30% di capacità di accumulo relativa all\'impianto solare</li><li>Durata Accumulo: Sistema di accumulo energia di 2 ore</li><li>Funzioni: Levigatura output, tracciamento programma, shaving picchi</li></ul><h3>Risultati Operativi</h3><p>La precisione di previsione dell\'energia solare è migliorata sopra il 95%, la fluttuazione dell\'output è ridotta dell\'80%.</p>','/uploads/cases/case-6-thumb.jpg','/uploads/cases/case-6-banner.jpg','[\"Solare+Accumulo\", \"Energia Rinnovabile\", \"Levigatura Output\"]','[2]',NULL,2456,'','2',NULL),(37,1,'2026-03-22 18:38:08.000000','2026-03-22 18:38:08.000000','福建海上风电储能 | 鹏成新能源案例','福建海上风电, 海上储能, 风电配套储能, 高防腐','鹏成新能源福建平潭400MW海上风电配套40MW/80MWh储能项目案例。',7,1,6,1,'福建海上风电储能配套项目','<h3>项目概况</h3><p>福建省平潭海上风电场400MW项目配套40MW/80MWh储能系统，解决海上风电出力间歇性问题。</p><h3>技术方案</h3><ul><li>海上平台：高防腐等级储能系统，适应高盐雾环境</li><li>储能配置：按风电装机10%配置储能</li><li>功能模式：平滑出力、计划跟踪、故障穿越支撑</li><li>远程监控：海上无人值守，岸上集中监控</li></ul><h3>项目特色</h3><p>国内首个海上风电配套储能项目，储能系统与海上平台一体化设计，年平滑出力效果提升25%。</p>','/uploads/cases/case-7-thumb.jpg','/uploads/cases/case-7-banner.jpg','[\"海上风电\", \"海上储能\", \"防腐系统\"]','[2]',NULL,4234,'','2',NULL),(38,1,'2026-03-22 18:38:08.000000','2026-03-22 18:38:08.000000','Fujian Offshore Wind Storage | Pengcheng Case','Fujian offshore wind, marine storage, wind storage, anti-corrosion','Pengcheng New Energy Fujian Pingtan 400MW offshore wind with 40MW/80MWh storage case.',7,2,6,1,'Fujian Offshore Wind + Storage Project','<h3>Project Overview</h3><p>A 40MW/80MWh energy storage system for the 400MW Pingtan offshore wind farm in Fujian Province, addressing the intermittency issues of offshore wind power output.</p><h3>Technical Solution</h3><ul><li>Offshore Platform: High anti-corrosion storage system adapted to high salt spray environment</li><li>Storage Configuration: 10% storage capacity relative to wind installation</li><li>Function Modes: Output smoothing, schedule tracking, fault ride-through support</li><li>Remote Monitoring: Unmanned offshore platform, centralized onshore monitoring</li></ul><h3>Project Features</h3><p>China\'s first offshore wind farm with supporting energy storage, integrated design of storage system and offshore platform, annual output smoothing effectiveness improved by 25%.</p>','/uploads/cases/case-7-thumb.jpg','/uploads/cases/case-7-banner.jpg','[\"Offshore Wind\", \"Marine Storage\", \"Anti-Corrosion\"]','[2]',NULL,5123,'','2',NULL),(39,1,'2026-03-22 18:38:08.000000','2026-03-22 18:38:08.000000','福建省洋上風力貯蔵 | 鵬成新能源ケース','福建省洋上風力, 海洋貯蔵, 風力貯蔵, 高防食','鵬成新能源福建省平潭400MW洋上風力40MW/80MWh貯蔵ケーススタディ。',7,3,6,1,'福建省洋上風力+貯蔵プロジェクト','<h3>プロジェクト概要</h3><p>福建省平潭洋上風力発電所400MWプロジェクトに40MW/80MWhのエネルギー貯蔵システムを配備し、洋上風力の出力間欠性問題に対処します。</p><h3>技術ソリューション</h3><ul><li>洋上プラットフォーム：高防食等級貯蔵システム、高塩分環境に適応</li><li>貯蔵構成：風力設備の10%の貯蔵容量</li><li>機能モード：出力平滑化、計画追跡、故障耐過渡支援</li><li>遠隔監視：洋上無人運転