DROP TABLE IF EXISTS `news`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `news` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `status` tinyint(4) NOT NULL DEFAULT '1',
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_keywords` text,
  `meta_description` text,
  `news_id` int(11) NOT NULL,
  `lang_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `content` longtext,
  `publish_at` datetime DEFAULT NULL,
  `view_count` int(11) NOT NULL DEFAULT '0',
  `thumb_url` varchar(512) DEFAULT NULL,
  `summary` text,
  `category_id` int(11) DEFAULT NULL,
  `is_top` tinyint(4) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `FK_f3924b9d61057e4f0cd76a49298` (`lang_id`),
  KEY `FK_aac53a9364896452e463139e4a0` (`category_id`),
  CONSTRAINT `FK_aac53a9364896452e463139e4a0` FOREIGN KEY (`category_id`) REFERENCES `news_category` (`id`) ON DELETE SET NULL ON UPDATE NO ACTION,
  CONSTRAINT `FK_f3924b9d61057e4f0cd76a49298` FOREIGN KEY (`lang_id`) REFERENCES `lang` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=160 DEFAULT CHARSET=utf8;
