DROP TABLE IF EXISTS `product`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `product` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `status` tinyint(4) NOT NULL DEFAULT '1',
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_keywords` text,
  `meta_description` text,
  `product_id` int(11) NOT NULL,
  `lang_id` int(11) NOT NULL,
  `name` varchar(255) NOT NULL,
  `thumb_url` varchar(512) DEFAULT NULL,
  `main_pics` json DEFAULT NULL,
  `model` varchar(128) DEFAULT NULL,
  `features` json DEFAULT NULL,
  `core_params` json DEFAULT NULL,
  `summary` text,
  `banner_url` varchar(512) DEFAULT NULL,
  `params_json` json DEFAULT NULL,
  `advantage_summary` varchar(512) DEFAULT NULL,
  `advantages` json DEFAULT NULL,
  `view_count` int(11) NOT NULL DEFAULT '0',
  `certifications` json DEFAULT NULL,
  `category_id` int(11) DEFAULT NULL,
  `detail_title` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK_42ee3056f65db5db0afce51eaf8` (`lang_id`),
  KEY `FK_0dce9bc93c2d2c399982d04bef1` (`category_id`),
  CONSTRAINT `FK_0dce9bc93c2d2c399982d04bef1` FOREIGN KEY (`category_id`) REFERENCES `product_category` (`id`) ON DELETE SET NULL ON UPDATE NO ACTION,
  CONSTRAINT `FK_42ee3056f65db5db0afce51eaf8` FOREIGN KEY (`lang_id`) REFERENCES `lang` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=420 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

