DROP TABLE IF EXISTS `product_category`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `product_category` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `status` tinyint(4) NOT NULL DEFAULT '1',
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `category_id` int(11) DEFAULT NULL,
  `name` varchar(128) NOT NULL,
  `lang_id` int(11) NOT NULL,
  `banner_url` varchar(512) DEFAULT NULL,
  `sort` int(11) NOT NULL DEFAULT '0',
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_keywords` text,
  `meta_description` text,
  `parent_id` int(11) NOT NULL DEFAULT '0',
  `menu_pic_url` varchar(512) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK_01ae17dd9ecceed192bdff1e36a` (`lang_id`),
  CONSTRAINT `FK_01ae17dd9ecceed192bdff1e36a` FOREIGN KEY (`lang_id`) REFERENCES `lang` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=611 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

